// =============================================================================
// SOFIA - Formateador de Respuesta
// Extrae output del agente y estructura la respuesta para el backend NestJS
// =============================================================================

const agentOutput = $input.first().json;

// Obtener el texto de respuesta del agente
const responseText = agentOutput.output 
  || agentOutput.text 
  || agentOutput.response 
  || 'Lo siento, no pude generar una respuesta en este momento. Por favor, intenta de nuevo.';

// Extraer herramientas usadas y fuentes de los pasos intermedios
const steps = agentOutput.intermediateSteps || [];
const sourcesCited = [];
const toolsUsed = [];

for (const step of steps) {
  try {
    // Registrar herramienta usada
    if (step.action && step.action.tool) {
      if (!toolsUsed.includes(step.action.tool)) {
        toolsUsed.push(step.action.tool);
      }
    }

    // Extraer fuentes de la herramienta de búsqueda RAG
    if (step.action && step.action.tool === 'buscar_conocimiento' && step.observation) {
      let observation = step.observation;

      // Parsear si es string JSON
      if (typeof observation === 'string') {
        observation = JSON.parse(observation);
      }

      // Extraer títulos de documentos únicos
      if (observation && observation.chunks && Array.isArray(observation.chunks)) {
        for (const chunk of observation.chunks) {
          const title = chunk.documentTitle || chunk.document_title;
          if (title && !sourcesCited.includes(title)) {
            sourcesCited.push(title);
          }
        }
      }
    }
  } catch (e) {
    // Ignorar errores de parseo individuales
    continue;
  }
}

// Estimación de tokens (aproximación: ~3 caracteres por token para español)
const approxTokens = Math.ceil(responseText.length / 3);

// Costo aproximado Claude Haiku: ~$0.80 por 1M tokens de salida
const approxCostUsd = (approxTokens / 1000000) * 0.80;

return [{
  json: {
    response: responseText,
    agentName: 'SofiaMainAgent',
    sourcesCited: sourcesCited.length > 0 ? sourcesCited : null,
    toolsUsed: toolsUsed.length > 0 ? toolsUsed : [],
    tokenCount: approxTokens,
    modelUsed: 'claude-haiku-4-5-20251001',
    costUsd: parseFloat(approxCostUsd.toFixed(8)),
    latencyMs: 0
  }
}];
